// Extract and validate input
const body = $input.first().json.body || $input.first().json;

const repoUrl = body.repo_url || body.repository?.clone_url || '';
const branch = body.branch || body.pull_request?.head?.ref || 'main';
const prNumber = body.pr_number || body.pull_request?.number || 0;
const prTitle = body.pr_title || body.pull_request?.title || 'Unknown';
const prDesc = body.pr_description || body.pull_request?.body || '';
const projectKey = body.project_key || body.sonar_project_key || 'default-project';
const commitSha = body.commit_sha || body.pull_request?.head?.sha || '';

// Classification
const critPatterns = /auth|login|password|token|payment|billing|encrypt|crypto|secret|migration/i;
let classification = 'STANDARD';
if (critPatterns.test(prTitle) || critPatterns.test(branch)) {
  classification = 'CRITICAL';
}
if (body.classification) classification = body.classification;

return [{ json: {
  repo_url: repoUrl,
  branch: branch,
  pr_number: prNumber,
  pr_title: prTitle,
  pr_description: prDesc,
  project_key: projectKey,
  commit_sha: commitSha,
  classification: classification,
  pipeline_start: Date.now()
} }];

// Process pipeline results
const result = $input.first().json;
const startTime = $('2. Prepare Input').first().json.pipeline_start;

const reportUrl = result.stages?.report?.download_url 
  ? `http://localhost:8585${result.stages.report.download_url}`
  : null;

return [{ json: {
  status: result.status,
  pipeline_id: result.pipeline_id,
  duration_seconds: result.duration_seconds,

  stages: {
    scan: result.stages?.scan?.status || 'unknown',
    scan_issues: result.stages?.scan?.issues_found || 0,
    context: result.stages?.context?.status || 'unknown',
    needs_ai: result.stages?.context?.needs_ai || false,
    ai_review: result.stages?.ai_review?.status || 'unknown',
    risk_level: result.stages?.ai_review?.risk || 'N/A',
    model_used: result.stages?.ai_review?.model || 'N/A',
    report: result.stages?.report?.status || 'unknown'
  },

  report: {
    filename: result.stages?.report?.filename || null,
    download_url: reportUrl,
    size_kb: result.stages?.report?.report_size_kb || 0
  },

  error: result.error || null
} }];
